import{bQ as s,aL as a,u as t,G as n}from"./chunks/framework.D06dwy5q.js";const o="/kb/assets/k8s-prometheus-targets-apiserver-annotated.BiYUGgpb.png",d="/kb/assets/k8s-prometheus-targets-coredns-annotated.C8_OoqyU.png",r="/kb/assets/k8s-prometheus-query-apiserver-requests-annotated.BPiXtTIX.png",p="/kb/assets/k8s-prometheus-query-coredns-rcode-annotated.C2BUrEPY.png",k=JSON.parse('{"title":"控制平面监控","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/14-控制平面监控.md","filePath":"12.可观测性与监控告警/14-控制平面监控.md","lastUpdated":null}'),c={name:"12.可观测性与监控告警/14-控制平面监控.md"};function l(i,e,h,u,b,g){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="控制平面监控" tabindex="-1">控制平面监控 <a class="header-anchor" href="#控制平面监控" aria-label="Permalink to &quot;控制平面监控&quot;">​</a></h1><p>Kubernetes 控制平面负责保存集群状态、处理 API 请求、调度 Pod、维护控制器循环和服务发现。控制平面异常时，已经运行的业务 Pod 可能还在工作，但新发布、扩缩容、配置下发、服务发现和事件写入都会受到影响。</p><p>K3s 的控制平面和 kubeadm 集群不完全一样。API Server 仍然是集群入口，CoreDNS 仍然负责集群内域名解析；Scheduler、Controller Manager 在 K3s server 进程里，默认暴露和采集方式需要单独处理。</p><h2 id="一、prometheus-target" tabindex="-1">一、Prometheus Target <a class="header-anchor" href="#一、prometheus-target" aria-label="Permalink to &quot;一、Prometheus Target&quot;">​</a></h2><p>控制平面监控先看 Prometheus 是否采到了目标。<code>up=1</code> 只能说明 Prometheus 能抓到 <code>/metrics</code>，具体是否慢、是否报错，还要继续查业务指标。</p><p>操作路径：</p><p><code>Status -&gt; Target health</code> （中文：状态 -&gt; 目标健康）</p><p>操作步骤：</p><ol><li>进入 <code>Status -&gt; Target health</code>。</li><li>在搜索框输入 <code>apiserver</code> 或 <code>coredns</code>。</li><li>查看对应 target 的 <code>State</code>、<code>Last scrape</code> 和展开后的 <code>Last error</code>。</li></ol><p>查看 API Server target：</p><p><img src="'+o+'" alt="Prometheus API Server target"></p><p>查看 CoreDNS target：</p><p><img src="'+d+`" alt="Prometheus CoreDNS target"></p><p>Target 常见字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>Endpoint</code></td><td>Prometheus 实际抓取的地址</td></tr><tr><td><code>Labels</code></td><td>这条 target 带上的标签，PromQL 聚合会用到</td></tr><tr><td><code>Last scrape</code></td><td>最近一次抓取时间和耗时</td></tr><tr><td><code>State</code></td><td><code>UP</code> 表示抓取成功，<code>DOWN</code> 表示抓取失败</td></tr></tbody></table><p>如果 target 是 <code>DOWN</code>，排查入口通常是 ServiceMonitor、Service、Endpoints 和证书。API Server 使用 HTTPS，证书和权限错误也会表现为抓取失败。</p><h2 id="二、api-server" tabindex="-1">二、API Server <a class="header-anchor" href="#二、api-server" aria-label="Permalink to &quot;二、API Server&quot;">​</a></h2><p>API Server 是 Kubernetes 的 HTTP API 入口。<code>kubectl</code>、kubelet、controller、scheduler、Operator 都会访问它。发布系统突然变慢、<code>kubectl get pod</code> 卡顿、Operator 一直重试时，API Server 的请求量、错误码和延迟是主要入口。</p><p>操作路径：</p><p><code>Query -&gt; Table</code> （中文：查询 -&gt; 表格）</p><p>操作步骤：</p><ol><li>进入 Prometheus <code>Query</code>。</li><li>选择 <code>Table</code>。</li><li>输入 PromQL。</li><li>点击 <code>Execute</code>。</li></ol><p>API Server 请求按动作、资源和状态码拆开：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sum by (verb, resource, code) (</span></span>
<span class="line"><span>  rate(apiserver_request_total[2m])</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><img src="`+r+`" alt="Prometheus 查询 API Server 请求"></p><p><code>verb</code> 表示动作，比如 <code>GET</code>、<code>LIST</code>、<code>WATCH</code>、<code>POST</code>、<code>PUT</code>、<code>PATCH</code>。<code>resource</code> 表示访问的对象，比如 <code>pods</code>、<code>nodes</code>、<code>configmaps</code>。<code>code</code> 是 HTTP 状态码。排查时先看是否有大量 <code>5xx</code>，再看是哪个资源和动作集中异常。</p><p>常用查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># API Server 每秒请求量，按动作、资源、状态码拆分</span></span>
<span class="line"><span>sum by (verb, resource, code) (</span></span>
<span class="line"><span>  rate(apiserver_request_total[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># API Server 5xx 错误，适合看服务端异常</span></span>
<span class="line"><span>sum by (verb, resource) (</span></span>
<span class="line"><span>  rate(apiserver_request_total{code=~&quot;5..&quot;}[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># API Server P99 延迟，按动作和资源拆开</span></span>
<span class="line"><span>histogram_quantile(</span></span>
<span class="line"><span>  0.99,</span></span>
<span class="line"><span>  sum by (le, verb, resource) (</span></span>
<span class="line"><span>    rate(apiserver_request_duration_seconds_bucket[5m])</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>API Server 延迟高时，常见方向有 etcd 慢、API 请求量突增、某个 controller 大量 list/watch、Webhook 变慢。K3s 默认使用 SQLite、外部数据库或嵌入式 etcd 的方式不同，排查时要按实际数据存储后端确认指标来源。</p><h2 id="三、coredns" tabindex="-1">三、CoreDNS <a class="header-anchor" href="#三、coredns" aria-label="Permalink to &quot;三、CoreDNS&quot;">​</a></h2><p>CoreDNS 负责集群内服务发现。Pod 通过 <code>svc.namespace.svc.cluster.local</code> 或短域名访问 Service 时，最终会走 CoreDNS。DNS 异常时，应用表现常见为连接数据库失败、服务间调用偶发超时、启动阶段解析域名失败。</p><p>CoreDNS 响应码可以快速判断解析结果：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sum by (rcode) (</span></span>
<span class="line"><span>  coredns_dns_responses_total</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><img src="`+p+`" alt="Prometheus 查询 CoreDNS 响应码"></p><p>常见响应码：</p><table tabindex="0"><thead><tr><th>响应码</th><th>含义</th></tr></thead><tbody><tr><td><code>NOERROR</code></td><td>解析成功</td></tr><tr><td><code>NXDOMAIN</code></td><td>域名不存在，常见于写错 Service 名或 namespace</td></tr><tr><td><code>SERVFAIL</code></td><td>服务端解析失败，常见于上游 DNS 或 CoreDNS 插件异常</td></tr><tr><td><code>REFUSED</code></td><td>查询被拒绝</td></tr></tbody></table><p>CoreDNS 常用查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># DNS 请求量，按查询类型拆开</span></span>
<span class="line"><span>sum by (type) (</span></span>
<span class="line"><span>  rate(coredns_dns_requests_total[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># DNS 响应码，适合看 NXDOMAIN / SERVFAIL 是否异常增长</span></span>
<span class="line"><span>sum by (rcode) (</span></span>
<span class="line"><span>  rate(coredns_dns_responses_total[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># DNS 请求耗时 P99</span></span>
<span class="line"><span>histogram_quantile(</span></span>
<span class="line"><span>  0.99,</span></span>
<span class="line"><span>  sum by (le) (</span></span>
<span class="line"><span>    rate(coredns_dns_request_duration_seconds_bucket[5m])</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><code>NXDOMAIN</code> 不一定是故障，有些应用会主动尝试多个域名。更有用的是把响应码和应用日志里的域名对上。比如发布后应用日志里出现 <code>lookup api.ops.svc.cluster.local: no such host</code>，同时 CoreDNS 的 <code>NXDOMAIN</code> 增长，再执行 <code>kubectl -n ops get svc api</code>。如果返回 <code>Error from server (NotFound): services &quot;api&quot; not found</code>，基本能确定不是 CoreDNS 坏了，而是调用方写了不存在的 Service 名、namespace 写错，或者 Service 还没创建。</p><p>如果 Service 能查到，但应用日志从 <code>no such host</code> 变成 <code>connect: connection timed out</code>，DNS 解析这一步已经过去了。此时再看 <code>kubectl -n ops get endpoints api</code>，如果 <code>ENDPOINTS</code> 是 <code>&lt;none&gt;</code>，问题更像 Service 后面没有 ready Pod，或者 selector 和 Pod label 对不上。</p><p><code>SERVFAIL</code> 更偏服务端解析失败。多个应用同时出现 <code>server misbehaving</code>、<code>i/o timeout</code> 这类 DNS 错误，CoreDNS 日志里又能看到 <code>plugin/errors: ... read udp ...: i/o timeout</code>，同时 DNS P99 耗时上涨，才往 CoreDNS Pod、上游 DNS 和节点网络方向查。</p><h2 id="四、scheduler-和-controller-manager" tabindex="-1">四、Scheduler 和 Controller Manager <a class="header-anchor" href="#四、scheduler-和-controller-manager" aria-label="Permalink to &quot;四、Scheduler 和 Controller Manager&quot;">​</a></h2><p>kubeadm 集群里 Scheduler、Controller Manager 通常是独立静态 Pod，也可以通过 ServiceMonitor 采集。K3s 里这些组件打包在 <code>k3s server</code> 进程中，默认暴露方式和 kubeadm 不一样。</p><p>在 K3s server 节点上可以查看监听端口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 10257 通常对应 kube-controller-manager</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 10259 通常对应 kube-scheduler</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> egrep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;:(10257|10259)\\b&#39;</span></span></code></pre></div><p>当前轻量部署中没有启用 <code>kubeControllerManager</code> 和 <code>kubeScheduler</code> 的抓取，避免 Prometheus 出现一批长期 <code>DOWN</code> 的 target。要采集这两个组件，需要同时确认监听地址、证书、Service、Endpoints 和 ServiceMonitor。</p><p>K3s 场景里，调度和控制器异常可以从这些现象进入：</p><table tabindex="0"><thead><tr><th>现象</th><th>入口</th></tr></thead><tbody><tr><td>Pod 长期 Pending</td><td><code>kubectl describe pod</code> 查看调度事件</td></tr><tr><td>Deployment 副本不上来</td><td><code>kube_deployment_status_replicas_unavailable</code> 和 Events</td></tr><tr><td>Job 不执行或失败</td><td><code>kube_job_status_failed</code>、CronJob 调度时间</td></tr><tr><td>控制器更新慢</td><td>API Server 请求延迟、controller 日志、对象状态变化</td></tr></tbody></table><h2 id="五、排错入口" tabindex="-1">五、排错入口 <a class="header-anchor" href="#五、排错入口" aria-label="Permalink to &quot;五、排错入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>检查入口</th><th>常见原因</th></tr></thead><tbody><tr><td><code>apiserver</code> target <code>DOWN</code></td><td><code>Status -&gt; Target health</code> 展开 <code>Last error</code></td><td>证书、权限、ServiceMonitor、Endpoints 异常</td></tr><tr><td><code>coredns</code> target <code>DOWN</code></td><td><code>Status -&gt; Target health</code> 和 <code>kubectl -n kube-system get pod</code></td><td>CoreDNS Pod 异常、ServiceMonitor 选择器不匹配</td></tr><tr><td>PromQL 查询为空</td><td>Prometheus <code>Query</code>、右上角时间范围、主机时间</td><td>指标不存在、时间范围不对、节点时间漂移</td></tr><tr><td>API Server 5xx 增加</td><td><code>apiserver_request_total{code=~&quot;5..&quot;}</code></td><td>API Server 内部异常、etcd 或 webhook 变慢</td></tr><tr><td>DNS <code>NXDOMAIN</code> 增加</td><td><code>coredns_dns_responses_total{rcode=&quot;NXDOMAIN&quot;}</code></td><td>Service 名、namespace、搜索域写错</td></tr><tr><td>DNS <code>SERVFAIL</code> 增加</td><td>CoreDNS 日志和上游 DNS</td><td>上游 DNS 异常、CoreDNS 插件异常</td></tr></tbody></table><p>Prometheus 和浏览器时间差太大时，页面会出现 <code>Server time is out of sync</code>。比如查询最近 5 分钟没有数据，但把时间范围拉到 1 小时又能看到曲线，<code>timedatectl status</code> 里 NTP 还是 <code>inactive</code>，基本就要先修主机时间同步。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看当前时间源和同步状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chronyc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sources</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看系统时间、时区和 NTP 状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">timedatectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div>`,52)])])}const v=s(c,[["render",l]]);export{k as __pageData,v as default};
